    args = [[]]
    depth = 0
    for _ in range(max(1, size)):
        r = rng.random()
        if depth > 0 and r < 0.4:
            ops.append('pop'); args.append([]); depth -= 1
        elif depth > 0 and r < 0.6:
            ops.append(rng.choice(['peek', 'empty'])); args.append([])
        else:
            ops.append('push'); args.append([rng.randint(1, 9)]); depth += 1
    ops.append('empty'); args.append([])
    return [ops, args]

