class MyQueue {
    constructor() {
        this.inbox = [];
        this.outbox = [];
    }
    push(x) {
        this.inbox.push(x);
    }
    _shift() {
        if (this.outbox.length === 0) {
            while (this.inbox.length) this.outbox.push(this.inbox.pop());
        }
    }
    pop() {
        this._shift();
        return this.outbox.pop();
    }
    peek() {
        this._shift();
        return this.outbox[this.outbox.length - 1];
    }
    empty() {
        return this.inbox.length === 0 && this.outbox.length === 0;
    }
}
